import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS attacks
        userInput = sanitizeUserInput(userInput);

        // Output sanitized user input to the response
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Hello, " + userInput + "</h1>");
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeUserInput(String input) {
        // Implement proper input sanitization based on your application requirements
        // For example, you can use OWASP Java Encoder or HTML escaping libraries
        return HtmlUtils.htmlEscape(input);
    }
}

